using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Raise the max request body size (default is ~30 MB)
builder.WebHost.ConfigureKestrel(o => o.Limits.MaxRequestBodySize = 50 * 1024 * 1024);

var app = builder.Build();

app.MapPost("/upload", async (IFormFileCollection files, HttpRequest request) =>
{
    // Read the text field from the multipart form
    var description = request.Form["description"].ToString();

    if (files.Count == 0)
        return Results.BadRequest("No files uploaded.");

    var savedFiles = new List<string>();

    foreach (var file in files)
    {
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"'{file.FileName}' is not an image.");

        var path = Path.Combine("uploads", file.FileName);
        Directory.CreateDirectory("uploads");

        await using var stream = File.Create(path);
        await file.CopyToAsync(stream);
        savedFiles.Add(file.FileName);
    }

    return Results.Ok(new { description, uploadedFiles = savedFiles });
})
.DisableAntiforgery()
.WithRequestFormLimits(multipartBodyLengthLimit: 50 * 1024 * 1024);

app.Run();
```

**Key points:**

- `ConfigureKestrel` raises the max request body to 50 MB.
- `.WithRequestFormLimits(...)` raises the multipart form limit to match.
- `IFormFileCollection` binds all uploaded files; the `description` field is read from `request.Form`.
- `.DisableAntiforgery()` is needed for minimal APIs that accept form data without an antiforgery token.

**Example `curl` call:**

```bash
curl -X POST http://localhost:5000/upload \
  -F "files=@photo1.jpg" \
  -F "files=@photo2.png" \
  -F "description=Vacation photos"
```
